    postUpdate () {

    }

    destroy () {
      this.owner.off( "levelSwitch", this.destroy, this );

      // Detach custom event listeners.
      this.owner.removeListener( this.owner.EVENTS.LEVEL_START, this.onLevelStart2, this );

    }

    // CUSTOM METHODS

    onCreate () {
      // Executed when this script is initially created.
      this.owner.tags.add( 'player' );
    }

    EVENTS_UPDATE () {
      // Executed every frame.
      this.camera.centerOn( this.owner.x, this.owner.y );
      if (( this.scene.getKey( 39 ).isDown || this.scene._keys.lastPressed === 39 )) {
        this.owner.body.velocity.x = 200;
        this.owner.flipX = false;
      } else if (( this.scene.getKey( 37 ).isDown || this.scene._keys.lastPressed === 37 )) {
        this.owner.body.velocity.x = (-200);
        this.owner.flipX = true;
      } else {
        this.owner.body.velocity.x = 0;
      }
      if (( this.scene.getKey( 38 ).isDown || this.scene._keys.lastPressed === 38 )) {
        if (( this.owner.body.touching.down || this.owner.body.blocked.down )) {
          this.owner.body.velocity.y = (-450);
        }
      }
      if (( this.owner.body.touching.down || this.owner.body.blocked.down )) {
        if (this.owner.body.velocity.x != 0) {
          this.owner.playMy( 'run' );
        } else {
          this.owner.playMy( 'idle' );
        }
      } else {
        if (this.owner.body.velocity.y < -10) {
          this.owner.playMy( 'jumpUp' );
        } else if (this.owner.body.velocity.y > 10) {
          this.owner.playMy( 'jumpDown' );
        }
      }
    }

    onLevelStart2() {
      this.scene.physics.world.gravity.y = 1000;
      this.owner.body.allowGravity = true;
      this.owner.playMy( 'idle' );

    }

  }
);

